@Suite(.serialized)
struct AuthSignupTests {
    let app: Application
    let testWorld: IsolatedTestWorld
    let registerPath = "api/v1/auth/sign-up"

    init() async throws {
        testWorld = try await IsolatedTestWorld()
        app = testWorld.app
    }

    @Test("User registration succeeds with valid data") 
    func registerHappyPath() async throws {
        await testWorld.resetAll() // Clean state before test
        // TestWorld already configures random generator with "test_random_value"
        // No need to reconfigure - just use the TestWorld configured value

        let data = Auth.SignUp.Request(
            email: "test@test.com",
            password: "password123",
            firstName: "Test",
            lastName: "User"
        )

        try await app.test(.POST, registerPath, beforeRequest: { req in
            try req.content.encode(data)
        }, afterResponse: { res async throws in
            #expect(res.status == .ok)
            expectContent(Auth.SignUp.Response.self, res) { signup in
                #expect(signup.user.email == "test@test.com")
                #expect(signup.user.firstName == "Test")
                #expect(signup.user.lastName == "User")
                #expect(signup.user.isAdmin == false)
                #expect(signup.user.isEmailVerified == false)

                // Verify tokens are not empty
                #expect(!signup.token.refreshToken.isEmpty)
                #expect(!signup.token.accessToken.isEmpty)
            }

            // Extract signup response to perform async database checks
            let content = try res.content.decode(Auth.SignUp.Response.self)

            // Verify user was created in database
            let model = try await app.repositories.users.find(id: content.user.id)
            #expect(model != nil, "User should exist in database")
            guard let foundModel = model else {
                Issue.record("User not found in database")
                return
            }
            guard let password = foundModel.password else {
                Issue.record("User password is nil")
                return
            }
            // In test environment, passwords are stored as plaintext (configured in TestWorld)
            #expect(password == "password123", "Password should be stored as plaintext in test environment")

            // TODO: Restore email token verification when email verification is re-enabled
            // let emailToken = try await app.repositories.emailTokens.find(forUserID: content.user.id)
            // XCTAssertNotNil(emailToken)
            // XCTAssertEqual(emailToken?.$user.id, content.user.id)
        })
    }

    @Test("Registration fails when email already exists")
    func registerFailsWithExistingEmail() async throws {
        await testWorld.resetAll() // Clean state before test
        // Create a user first using the test repository
        let existingUser = UserAccountModel(
            email: "test@test.com",
            password: "123"
        )
        try await app.repositories.users.create(existingUser)

        // Try to register with the same email
        let registerRequest = Auth.SignUp.Request(
            email: "test@test.com",
            password: "password123",
            firstName: "Test",
            lastName: "User"
        )

        try await app.test(.POST, registerPath, beforeRequest: { req in
            try req.content.encode(registerRequest)
        }, afterResponse: { res async throws in
            expectResponseError(res, AuthenticationError.emailAlreadyExists)
            // Verify only one user exists in the test repository
            let users = try await app.repositories.users.all()
            #expect(users.count == 1)
        })
    }

    @Test("Registration validates email and password requirements")
    func registerValidations() async throws {
        await testWorld.resetAll() // Clean state before test
        // TestWorld already configures random generator with "test_random_value"

        let data = Auth.SignUp.Request(
            email: "TEStest.com",  // Invalid email
            password: "pass",       // Too short password
            firstName: "Test",
            lastName: "User"
        )

        try await app.test(.POST, registerPath, beforeRequest: { req in
            try req.content.encode(data)
        }, afterResponse: { res in
            #expect(res.status == .badRequest)
            expectContent(ErrorResponse.self, res) { error in
                #expect(error.reason == "email is not a valid email address, password is less than minimum of 8 character(s)")
            }
        })
    }

    @Test("Registration converts email to lowercase")
    func registerLowercaseEmail() async throws {
        await testWorld.resetAll() // Clean state before test
        // TestWorld already configures random generator with "test_random_value"

        let data = Auth.SignUp.Request(
            email: "TEST@test.com",
            password: "password123",
            firstName: "Test",
            lastName: "User"
        )

        try await app.test(.POST, registerPath, beforeRequest: { req in
            try req.content.encode(data)
        }, afterResponse: { res in
            #expect(res.status == .ok)
            expectContent(Auth.SignUp.Response.self, res) { signup in
                #expect(signup.user.email == "test@test.com")
            }
        })
    }

    @Test("Registration works with optional fields omitted")
    func registerWithOptionalFields() async throws {
        await testWorld.resetAll() // Clean state before test
        // TestWorld already configures random generator with "test_random_value"

        // Test with no first/last name
        let data = Auth.SignUp.Request(
            email: "test@test.com",
            password: "password123",
            firstName: nil,
            lastName: nil
        )

        try await app.test(.POST, registerPath, beforeRequest: { req in
            try req.content.encode(data)
        }, afterResponse: { res in
            #expect(res.status == .ok)
            expectContent(Auth.SignUp.Response.self, res) { signup in
                #expect(signup.user.email == "test@test.com")
                #expect(signup.user.firstName == nil)
                #expect(signup.user.lastName == nil)
            }
        })
    }

    @Test("Registration treats empty strings as nil for optional fields")
    func registerWithEmptyOptionalFields() async throws {
        await testWorld.resetAll() // Clean state before test
        // TestWorld already configures random generator with "test_random_value"

        // Test with empty strings (should be converted to nil)
        let data = Auth.SignUp.Request(
            email: "test@test.com",
            password: "password123",
            firstName: "",
            lastName: "  " // whitespace should be treated as empty
        )

        try await app.test(.POST, registerPath, beforeRequest: { req in
            try req.content.encode(data)
        }, afterResponse: { res in
            #expect(res.status == .ok)
            expectContent(Auth.SignUp.Response.self, res) { signup in
                #expect(signup.user.email == "test@test.com")
                #expect(signup.user.firstName == nil) // Empty string should become nil
                #expect(signup.user.lastName == nil)  // Whitespace should become nil
            }
        })
    }
}

import Foundation

/// Configuration for operation-specific rate limiting with tiered protection levels.
///
/// This configuration implements a sophisticated rate limiting strategy that applies
/// different limits based on the type and cost of operations, providing optimal
/// protection while maintaining good user experience.
///
/// ## Rate Limiting Strategy
/// 
/// The system uses a **tiered approach** with increasingly restrictive limits based on:
/// - **Resource Cost**: AI operations consume external API credits
/// - **Security Risk**: Admin operations require stricter controls
/// - **User Impact**: Balance between protection and usability
/// - **Business Logic**: Different limits for different application areas
///
/// ## Tier Structure
/// 
/// 1. **AI Operations** (Most Restrictive)
///    - Image analysis and rules generation
///    - High cost operations using external AI APIs
///    - Strict limits to prevent abuse and cost overruns
///
/// 2. **Admin Operations** (Restricted)
///    - Administrative endpoints and cache management
///    - Security-sensitive operations requiring careful access control
///    - Moderate limits balancing security with administrative needs
///
/// 3. **API Operations** (Moderate)
///    - General API endpoints for application functionality
///    - Standard business operations with reasonable resource usage
///    - Balanced limits supporting normal application usage
///
/// 4. **General Operations** (Lenient)  
///    - Web page requests and static content
///    - Low-cost operations with minimal security impact
///    - Generous limits supporting good user experience
///
/// ## Environment-Specific Configurations
/// 
/// - **Production**: Conservative limits optimized for cost control and security
/// - **Development**: Relaxed limits supporting development and testing workflows
/// - **Default**: Balanced limits suitable for most deployment scenarios
struct RateLimitConfiguration {

    // MARK: - AI Operation Limits (Tier 1 - Most Restrictive)

    /// Maximum number of image analysis requests allowed within the time window.
    ///
    /// Image analysis operations are the most expensive, using OpenAI's vision API
    /// which has higher per-request costs than text generation.
    ///
    /// **Production**: 3 requests/hour (very conservative)
    /// **Development**: 50 requests/hour (testing-friendly)
    let imageAnalysisLimit: Int

    /// Time window for image analysis rate limiting in seconds.
    ///
    /// Uses 1-hour windows to provide reasonable daily allowances while
    /// preventing burst usage that could exhaust API quotas.
    let imageAnalysisWindow: Int

    /// Maximum number of rules generation requests allowed within the time window.
    ///
    /// Rules generation uses text-based AI models which are less expensive than
    /// vision models but still consume significant API credits.
    ///
    /// **Production**: 5 requests/hour
    /// **Development**: 100 requests/hour
    let rulesGenerationLimit: Int

    /// Time window for rules generation rate limiting in seconds.
    let rulesGenerationWindow: Int

    // MARK: - Admin Operation Limits (Tier 2 - Restricted)

    /// Maximum number of admin requests allowed within the time window.
    ///
    /// Administrative operations require elevated privileges and could impact
    /// system state, requiring careful rate limiting for security.
    ///
    /// **Production**: 10 requests/5 minutes
    /// **Development**: 200 requests/5 minutes
    let adminLimit: Int

    /// Time window for admin rate limiting in seconds.
    ///
    /// Uses shorter 5-minute windows for admin operations to quickly throttle
    /// potential abuse while allowing legitimate administrative tasks.
    let adminWindow: Int

    // MARK: - API Operation Limits (Tier 3 - Moderate)

    /// Maximum number of general API requests allowed within the time window.
    ///
    /// Covers standard application API endpoints including user management,
    /// authentication, and basic CRUD operations.
    ///
    /// **Production**: 50 requests/hour
    /// **Development**: 1000 requests/hour
    let apiLimit: Int

    /// Time window for API rate limiting in seconds.
    let apiWindow: Int

    // MARK: - General Operation Limits (Tier 4 - Lenient)

    /// Maximum number of general web requests allowed within the time window.
    ///
    /// Applies to static content, web pages, and other low-cost operations
    /// that don't consume significant server resources.
    ///
    /// **Production**: 500 requests/hour
    /// **Development**: 10,000 requests/hour
    let generalLimit: Int

    /// Time window for general request rate limiting in seconds.
    let generalWindow: Int

    // MARK: - Waitlist Operation Limits

    /// Maximum number of waitlist subscription requests allowed within the time window.
    ///
    /// Waitlist operations protect against automated spam while allowing legitimate signups.
    ///
    /// **Production**: 10 requests/hour
    /// **Development**: 100 requests/hour
    let waitlistLimit: Int

    /// Time window for waitlist rate limiting in seconds.
    let waitlistWindow: Int

    /// Default rate limiting configuration suitable for most deployments.
    ///
    /// Provides balanced limits that protect against abuse while supporting
    /// normal application usage patterns. This configuration is recommended
    /// for staging environments and initial production deployments.
    ///
    /// ## Limit Summary
    /// - **Image Analysis**: 5 requests/hour (moderate protection)
    /// - **Rules Generation**: 10 requests/hour (reasonable for typical usage)
    /// - **Admin Operations**: 20 requests/5 minutes (administrative flexibility)
    /// - **API Operations**: 100 requests/hour (supports active usage)
    /// - **General Requests**: 1000 requests/hour (generous for web browsing)
    static let `default` = RateLimitConfiguration(
        // AI operations: Very restrictive to prevent abuse
        imageAnalysisLimit: 5,
        imageAnalysisWindow: 3600, // 1 hour
        rulesGenerationLimit: 10,
        rulesGenerationWindow: 3600, // 1 hour

        // Admin operations: Restricted but reasonable
        adminLimit: 20,
        adminWindow: 300, // 5 minutes

        // API operations: Moderate limits
        apiLimit: 100,
        apiWindow: 3600, // 1 hour

        // General web requests: Lenient
        generalLimit: 1000,
        generalWindow: 3600, // 1 hour

        // Waitlist operations: Moderate protection
        waitlistLimit: 10,
        waitlistWindow: 3600 // 1 hour
    )

    /// Production rate limiting configuration optimized for cost control and security.
    ///
    /// Implements conservative limits designed for production environments where
    /// cost control, security, and stability are paramount. These limits prevent
    /// abuse while maintaining acceptable service for legitimate users.
    ///
    /// ## Production Optimizations
    /// - **Cost Control**: Strict AI operation limits prevent unexpected API costs
    /// - **Security Focus**: Restrictive admin limits reduce attack surface
    /// - **Stability**: Conservative limits ensure consistent performance
    /// - **Abuse Prevention**: Low limits make abuse economically unviable
    ///
    /// ## Limit Summary
    /// - **Image Analysis**: 3 requests/hour (very conservative)
    /// - **Rules Generation**: 5 requests/hour (cost-controlled)
    /// - **Admin Operations**: 10 requests/5 minutes (security-focused)
    /// - **API Operations**: 50 requests/hour (reasonable for production)
    /// - **General Requests**: 500 requests/hour (adequate for web usage)
    ///
    /// - Returns: Configuration optimized for production deployment
    static func production() -> RateLimitConfiguration {
        return RateLimitConfiguration(
            imageAnalysisLimit: 3,
            imageAnalysisWindow: 3600,
            rulesGenerationLimit: 5,
            rulesGenerationWindow: 3600,
            adminLimit: 10,
            adminWindow: 300,
            apiLimit: 50,
            apiWindow: 3600,
            generalLimit: 500,
            generalWindow: 3600,
            waitlistLimit: 10,
            waitlistWindow: 3600
        )
    }

    /// Development rate limiting configuration with relaxed limits for testing.
    ///
    /// Provides generous limits suitable for development and testing environments
    /// where developers need flexibility to iterate quickly and test various
    /// scenarios without hitting rate limits.
    ///
    /// ## Development Features
    /// - **Testing Flexibility**: High limits support extensive testing
    /// - **Developer Productivity**: Minimal throttling during development
    /// - **API Exploration**: Generous allowances for experimenting with features
    /// - **Load Testing**: Sufficient capacity for performance testing
    ///
    /// ## Limit Summary
    /// - **Image Analysis**: 50 requests/hour (testing-friendly)
    /// - **Rules Generation**: 100 requests/hour (extensive testing support)
    /// - **Admin Operations**: 200 requests/5 minutes (development flexibility)
    /// - **API Operations**: 1000 requests/hour (ample for development)
    /// - **General Requests**: 10,000 requests/hour (no practical limit)
    ///
    /// - Returns: Configuration optimized for development and testing
    static func development() -> RateLimitConfiguration {
        return RateLimitConfiguration(
            imageAnalysisLimit: 50,
            imageAnalysisWindow: 3600,
            rulesGenerationLimit: 100,
            rulesGenerationWindow: 3600,
            adminLimit: 200,
            adminWindow: 300,
            apiLimit: 1000,
            apiWindow: 3600,
            generalLimit: 10000,
            generalWindow: 3600,
            waitlistLimit: 100,
            waitlistWindow: 3600
        )
    }
}

@testable import App
import Foundation
import Vapor

/// Mock Rate Limit service for testing rate limiting scenarios.
///
/// This service provides utilities to manipulate the rate limit storage
/// for testing different rate limiting scenarios without requiring actual
/// HTTP requests to trigger rate limits.
final class MockRateLimitService: @unchecked Sendable {
    private let application: Application
    private let logger: Logger

    init(app: Application) {
        self.application = app
        self.logger = app.logger
    }

    // MARK: - Test Utilities

    /// Simulate requests to trigger rate limiting for a specific operation type and client IP.
    ///
    /// - Parameters:
    ///   - type: The rate limit type to simulate requests for
    ///   - clientIP: The client IP address to use
    ///   - count: Number of requests to simulate
    ///   - timeSpread: Time span over which to spread the requests (default: 0 for all at once)
    func simulateRequests(
        type: RateLimitType,
        clientIP: String,
        count: Int,
        timeSpread: TimeInterval = 0
    ) async {
        let operationKey = "\(type.rawValue)_\(clientIP)"
        let baseTime = Date()

        for i in 0..<count {
            let requestTime: Date
            if timeSpread > 0 {
                let offset = (timeSpread / Double(count)) * Double(i)
                requestTime = baseTime.addingTimeInterval(-offset)
            } else {
                requestTime = baseTime
            }

            await RateLimitStorage.shared.record(operationKey: operationKey, at: requestTime)
        }

        logger.info("Simulated \(count) requests for \(type.rawValue) from IP \(clientIP)")
    }

    /// Fill up the rate limit for a specific operation type to the maximum.
    ///
    /// - Parameters:
    ///   - type: The rate limit type to fill
    ///   - clientIP: The client IP address to use
    ///   - configuration: The rate limit configuration to use for determining limits
    func fillRateLimit(
        type: RateLimitType,
        clientIP: String,
        configuration: RateLimitConfiguration
    ) async {
        let maxRequests = getMaxRequests(for: type, configuration: configuration)
        await simulateRequests(type: type, clientIP: clientIP, count: maxRequests)
    }

    /// Check if a client would be rate limited for a specific operation type.
    ///
    /// - Parameters:
    ///   - type: The rate limit type to check
    ///   - clientIP: The client IP address to check
    ///   - configuration: The rate limit configuration to use
    /// - Returns: True if the client would be rate limited
    func wouldBeRateLimited(
        type: RateLimitType,
        clientIP: String,
        configuration: RateLimitConfiguration
    ) async -> Bool {
        let operationKey = "\(type.rawValue)_\(clientIP)"
        let windowSeconds = getWindowSeconds(for: type, configuration: configuration)
        let maxRequests = getMaxRequests(for: type, configuration: configuration)

        let cutoffTime = Date().addingTimeInterval(-Double(windowSeconds))
        let currentCount = await RateLimitStorage.shared.getCount(for: operationKey, since: cutoffTime)

        return currentCount >= maxRequests
    }

    /// Get the current request count for a specific operation and client.
    ///
    /// - Parameters:
    ///   - type: The rate limit type to check
    ///   - clientIP: The client IP address to check
    ///   - configuration: The rate limit configuration to use
    /// - Returns: Current number of requests in the time window
    func getCurrentCount(
        type: RateLimitType,
        clientIP: String,
        configuration: RateLimitConfiguration
    ) async -> Int {
        let operationKey = "\(type.rawValue)_\(clientIP)"
        let windowSeconds = getWindowSeconds(for: type, configuration: configuration)
        let cutoffTime = Date().addingTimeInterval(-Double(windowSeconds))

        return await RateLimitStorage.shared.getCount(for: operationKey, since: cutoffTime)
    }

    /// Reset all rate limit data.
    func resetAllRateLimits() async {
        let currentTime = Date()
        // Use a time far in the future to effectively clear all entries
        await RateLimitStorage.shared.cleanup(olderThan: currentTime.addingTimeInterval(1))
        logger.info("All rate limit data reset")
    }

    /// Get rate limit statistics for testing.
    func getStatistics() async -> [String: String] {
        // Return mock statistics for testing purposes
        return [
            "total_tracked_operations": "0",
            "total_requests": "0",
            "mock_service": "true"
        ]
    }

    // MARK: - Test Scenarios

    /// Set up a scenario where the client is just below the rate limit.
    ///
    /// - Parameters:
    ///   - type: The rate limit type
    ///   - clientIP: The client IP address
    ///   - configuration: The rate limit configuration
    func setupNearLimitScenario(
        type: RateLimitType,
        clientIP: String,
        configuration: RateLimitConfiguration
    ) async {
        let maxRequests = getMaxRequests(for: type, configuration: configuration)
        let requestsToSimulate = max(1, maxRequests - 2) // Leave 1-2 requests before limit
        await simulateRequests(type: type, clientIP: clientIP, count: requestsToSimulate)
    }

    /// Set up a scenario where the client has exceeded the rate limit.
    ///
    /// - Parameters:
    ///   - type: The rate limit type
    ///   - clientIP: The client IP address
    ///   - configuration: The rate limit configuration
    func setupExceededLimitScenario(
        type: RateLimitType,
        clientIP: String,
        configuration: RateLimitConfiguration
    ) async {
        let maxRequests = getMaxRequests(for: type, configuration: configuration)
        let requestsToSimulate = maxRequests + 5 // Exceed by 5 requests
        await simulateRequests(type: type, clientIP: clientIP, count: requestsToSimulate)
    }

    // MARK: - Private Helpers

    private func getMaxRequests(for type: RateLimitType, configuration: RateLimitConfiguration) -> Int {
        switch type {
        case .imageAnalysis:
            return configuration.imageAnalysisLimit
        case .rulesGeneration:
            return configuration.rulesGenerationLimit
        case .admin:
            return configuration.adminLimit
        case .api:
            return configuration.apiLimit
        case .general:
            return configuration.generalLimit
        case .waitlist:
            return configuration.waitlistLimit
        }
    }

    private func getWindowSeconds(for type: RateLimitType, configuration: RateLimitConfiguration) -> Int {
        switch type {
        case .imageAnalysis:
            return configuration.imageAnalysisWindow
        case .rulesGeneration:
            return configuration.rulesGenerationWindow
        case .admin:
            return configuration.adminWindow
        case .api:
            return configuration.apiWindow
        case .general:
            return configuration.generalWindow
        case .waitlist:
            return configuration.waitlistWindow
        }
    }
}

